def max_points(a):
    n = len(a)
    dp = [[0]*n for _ in range(n)]
    for i in range(n):
        dp[i][i] = a[i]
    for length in range(2, n+1):
        for i in range(n-length+1):
            j = i + length - 1
            dp[i][j] = max(a[i] - dp[i+1][j], a[j] - dp[i][j-1])
    return dp[0][n-1]

n = int(input())
a = list(map(int, input().split()))
print(max_points(a))

